#include<stdio.h>
#include<stdlib.h>
#include<string.h>
#include<math.h>

int main()
{
    int n,i,x,a[4],temp;
    scanf("%d%d",&n,&x);
    a[0]=0;
    a[1]=0;
    a[2]=0;
    a[x]=1;
    if(n>6) n=n%6;
    for(i=n;i>0;i--)
    {
        if(i%2==0)
        {
            temp=a[2];
            a[2]=a[1];
            a[1]=temp;
        }
        else
        {
            temp=a[0];
            a[0]=a[1];
            a[1]=temp;
        }
    }
    if(a[0]==1) printf("0");
    else if(a[1]==1) printf("1");
    else if(a[2]==1) printf("2");
    return 0;
}

