use std::io::{self, Stdin};
use std::str::{self, FromStr};
use std::error::Error;

fn exec() {
    let mut sc = Scanner::new();
    let n: usize = sc.ne();
    let mut a = [0, 1, 2];
    let m = n % 6;
    for k in 0..m {
        let tmp = a[1];
        if k & 1 == 0 {
            a[1] = a[0];
            a[0] = tmp;
        } else {
            a[1] = a[2];
            a[2] = tmp;
        }

    }
    let k: usize = sc.ne();
    println!("{}", a[k]);
}

fn main() {
    const STACK: usize = 16 * 1024 * 1024;
    let _ = std::thread::Builder::new()
        .stack_size(STACK)
        .spawn(|| { exec(); })
        .unwrap()
        .join()
        .unwrap();
}

